import React from 'react';
import { ChevronLeft, ShieldCheck, ArrowRight, Wallet, CreditCard } from 'lucide-react';
import { useCurrency } from '../context/CurrencyContext';

const ConfirmPaymentScreen = ({
  type = "Transaction",
  amount = 0,
  source = "Nest Balance",
  destination = "Savings Vault",
  fee = 0,
  onBack,

  onConfirm,

}) => {
  const { formatAmount } = useCurrency();

  const numericAmount = Number(amount) || 0;
  const numericFee = Number(fee) || 0;
  const total = numericAmount + numericFee;

  return (
    <div className="h-full bg-white flex flex-col animate-in slide-in-from-right duration-300">

      {/* Header */}
      <div className="p-6 flex items-center gap-3 border-b border-gray-50">
        <button
          onClick={onBack}
          className="p-2 bg-gray-50 rounded-full hover:bg-gray-100 transition-colors"
        >
          <ChevronLeft className="w-6 h-6 text-gray-800" />
        </button>
        <h1 className="text-xl font-black text-gray-900">Review {type}</h1>
      </div>

      {/* Body */}
      <div className="flex-1 p-8 overflow-y-auto scrollbar-hide">

        {/* Total Amount */}
        <div className="text-center mb-10">
          <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-2">
            Total to Pay
          </p>
          <h2 className="text-5xl font-black text-gray-900 tracking-tight">
            {formatAmount(total)}
          </h2>
        </div>

        {/* Source → Destination */}
        <div className="flex items-center justify-between p-6 bg-gray-50 rounded-[2.5rem] mb-10 border border-gray-100">
          <div className="flex flex-col items-center gap-2 flex-1">
            <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-gray-400 shadow-sm">
              {source.toLowerCase().includes("card") ? (
                <CreditCard size={24} />
              ) : (
                <Wallet size={24} />
              )}
            </div>
            <span className="text-[10px] font-black text-gray-800 uppercase text-center">
              {source}
            </span>
          </div>

          <div className="px-4 text-[#00875A] animate-pulse">
            <ArrowRight size={24} />
          </div>

          <div className="flex flex-col items-center gap-2 flex-1">
            <div className="w-12 h-12 bg-[#00875A] rounded-2xl flex items-center justify-center text-white shadow-lg">
              <ShieldCheck size={24} />
            </div>
            <span className="text-[10px] font-black text-gray-800 uppercase text-center">
              {destination}
            </span>
          </div>
        </div>

        {/* Breakdown */}
        <div className="space-y-4">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">
            Breakdown
          </label>

          <div className="bg-white border border-gray-100 rounded-[2rem] overflow-hidden">
            <div className="p-5 flex justify-between items-center">
              <span className="text-sm font-bold text-gray-500">Amount</span>
              <span className="font-black text-gray-900">
                {formatAmount(numericAmount)}
              </span>
            </div>

            <div className="p-5 flex justify-between items-center bg-gray-50/50 border-t border-gray-50">
              <span className="text-sm font-bold text-gray-500">Transaction Fee</span>
              <span className="font-black text-emerald-600">
                {numericFee === 0 ? "FREE" : formatAmount(numericFee)}
              </span>
            </div>

            <div className="p-5 flex justify-between items-center border-t border-gray-50">
              <span className="text-sm font-bold text-gray-800">Final Total</span>
              <span className="text-lg font-black text-[#00875A]">
                {formatAmount(total)}
              </span>
            </div>
          </div>
        </div>

        {/* Security Notice */}
        <div className="mt-8 p-5 bg-blue-50 rounded-[1.8rem] border border-blue-100 flex gap-4">
          <ShieldCheck className="text-blue-500 shrink-0" size={20} />
          <p className="text-[10px] text-blue-700 font-bold leading-relaxed">
            By clicking confirm, you authorize Nest to process this transaction.
            Funds will be moved instantly.
          </p>
        </div>
      </div>

      {/* Confirm Button */}
      <div className="p-6 flex justify-center">
        <button
          onClick={onConfirm}
          className="w-[90%] py-4 rounded-2xl font-bold bg-gray-900 text-white text-lg shadow-xl active:scale-[0.98] transition-all"
        >
          Confirm & Authorize
        </button>
      </div>
    </div>
  );
};

export default ConfirmPaymentScreen;
